#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=21;
int t,n;
bool use[N];
ll m,f[N][N][2];
void solve(){
    f[1][1][0]=f[1][1][1]=1;
    for(int i=2;i<N;i++)
        for(int j=1;j<=i;j++){
            for(int k=j;k<i;k++)
                f[i][j][0]+=f[i-1][k][1];
            for(int k=1;k<j;k++)
                f[i][j][1]+=f[i-1][k][0];
        }
}
int main(){
    solve();
    scanf("%d",&t);
    while(t--){
        memset(use,0,sizeof(use));
        scanf("%d%lld",&n,&m);
        int last,k;
        for(int j=1;j<=n;j++){
            if(f[n][j][1]>=m){
                last=j,k=1;
                break;
            }else
                m-=f[n][j][1];
            if(f[n][j][0]>=m){
                last=j,k=0;
                break;
            }else
                m-=f[n][j][0];
        }
        use[last]=1;
        printf("%d",last);
        for(int i=2;i<=n;i++){
            k=1-k;
            int j=0;
            for(int len=1;len<=n;len++){
                if(use[len])
                    continue;
                j++;
                if(k==0 && len<last || k==1 && len>last){
                    if(f[n-i+1][j][k]>=m){
                        last=len;
                        break;
                    }else
                        m-=f[n-i+1][j][k];
                }
            }
            use[last]=1;
            printf(" %d",last);
        }
        puts("");
    }
    return 0;
}
